import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { 
    AppBar, 
    Toolbar, 
    Typography, 
    Button, 
    Box,
    Container 
} from '@mui/material';
import FitnessCenterIcon from '@mui/icons-material/FitnessCenter';
import { useAuth } from '../contexts/AuthContext';

const Navbar = () => {
    const { user, logout } = useAuth();
    const navigate = useNavigate();

    const handleLogout = () => {
        logout();
        navigate('/login');
    };

    return (
        <AppBar position="static">
            <Container maxWidth="xl">
                <Toolbar disableGutters>
                    <FitnessCenterIcon sx={{ mr: 2 }} />
                    <Typography
                        variant="h6"
                        noWrap
                        component={Link}
                        to="/"
                        sx={{
                            mr: 2,
                            fontWeight: 700,
                            color: 'inherit',
                            textDecoration: 'none',
                            flexGrow: { xs: 1, md: 0 }
                        }}
                    >
                        Fitness Tracker
                    </Typography>

                    {user && (
                        <Box sx={{ flexGrow: 1, display: 'flex', ml: 3 }}>
                            <Button
                                component={Link}
                                to="/dashboard"
                                sx={{ color: 'white', mx: 1 }}
                            >
                                Dashboard
                            </Button>
                            <Button
                                component={Link}
                                to="/calendar"
                                sx={{ color: 'white', mx: 1 }}
                            >
                                Calendar
                            </Button>
                            <Button
                                component={Link}
                                to="/activities"
                                sx={{ color: 'white', mx: 1 }}
                            >
                                Activities
                            </Button>
                            <Button
                                component={Link}
                                to="/goals"
                                sx={{ color: 'white', mx: 1 }}
                            >
                                Goals
                            </Button>
                            <Button
                                component={Link}
                                to="/steps"
                                sx={{ color: 'white', mx: 1 }}
                            >
                                Steps
                            </Button>
                            <Button
                                component={Link}
                                to="/profile"
                                sx={{ color: 'white', mx: 1 }}
                            >
                                Profile
                            </Button>
                        </Box>
                    )}

                    {user ? (
                        <Button 
                            color="inherit" 
                            onClick={handleLogout}
                            sx={{ ml: 'auto' }}
                        >
                            Logout ({user.username})
                        </Button>
                    ) : (
                        <Box sx={{ ml: 'auto' }}>
                            <Button
                                component={Link}
                                to="/login"
                                sx={{ color: 'white' }}
                            >
                                Login
                            </Button>
                            <Button
                                component={Link}
                                to="/register"
                                sx={{ color: 'white' }}
                            >
                                Register
                            </Button>
                        </Box>
                    )}
                </Toolbar>
            </Container>
        </AppBar>
    );
};

export default Navbar;
